import {MapContainer,TileLayer,Marker,Polyline,useMap} from "react-leaflet"
import {useEffect,useState} from "react"
import {getBins,getRoute,updateBin} from "../services/api"
import L from "leaflet"
import "leaflet.heat"

function HeatmapLayer({bins}){

const map=useMap()

useEffect(()=>{

if(!bins.length) return

const heatData=bins.map(b=>[b.Latitude,b.Longitude,b.Waste_Level/100])

const heat=L.heatLayer(heatData,{radius:30,blur:25}).addTo(map)

return ()=>map.removeLayer(heat)

},[bins])

return null
}

export default function MapPage(){

const [bins,setBins]=useState([])
const [route,setRoute]=useState([])
const [binId,setBinId]=useState("")
const [waste,setWaste]=useState("")

function load(){
getBins().then(r=>setBins(r.data))
getRoute().then(r=>setRoute(r.data))
}

useEffect(()=>{load()},[])

function submit(){
updateBin({Bin_ID:binId,Waste_Level:Number(waste)}).then(load)
}

const coords=route.map(r=>[r.Latitude,r.Longitude])

return(
<div>
<h3>Bin Data (Live from Backend)</h3>

<table style={{width:"100%",background:"#1e293b",marginTop:"20px"}}>

<thead>
<tr>
<th>Bin ID</th>
<th>Area</th>
<th>Waste %</th>
</tr>
</thead>

<tbody>

{bins.map(bin => (

<tr key={bin.Bin_ID}>

<td>{bin.Bin_ID}</td>
<td>{bin.Area}</td>
<td>{bin.Waste_Level}%</td>

</tr>

))}

</tbody>

</table>
<h2>Heatmap + Smart Bin Map</h2>

<MapContainer center={[12.97,77.59]} zoom={11} className="map">

<TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"/>

<HeatmapLayer bins={bins}/>

{bins.map(b=>(
<Marker key={b.Bin_ID} position={[b.Latitude,b.Longitude]}/>
))}

<Polyline positions={coords} color="red"/>

</MapContainer>

<h3>Manual Bin Waste Entry</h3>

<input placeholder="Bin ID (B1..)" onChange={e=>setBinId(e.target.value)}/>
<input placeholder="Waste %" onChange={e=>setWaste(e.target.value)}/>
<button onClick={submit}>Update</button>

</div>

)
}
